using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

builder.Services.AddSingleton<ResearchTools>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(researchTools.WebSearch),
    AIFunctionFactory.Create(researchTools.TakeNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic, you must:
        1. Search the web for relevant information using the web_search tool (perform multiple searches to cover different angles).
        2. Take notes on key findings using the take_note tool.
        3. After gathering enough information, provide a comprehensive summary of your findings.

        Always search before summarizing. Be thorough and cite your sources.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):");
Console.Write("> ");

while (Console.ReadLine() is { } input && !input.Equals("quit", StringComparison.OrdinalIgnoreCase))
{
    if (string.IsNullOrWhiteSpace(input))
    {
        Console.Write("> ");
        continue;
    }

    Console.WriteLine($"\nResearching: {input}\n");

    var options = new ChatClientAgentRunOptions
    {
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
        },
    };

    var response = await agent.RunAsync(
        $"Research the following topic and provide a summary: {input}",
        session: null,
        options: options);

    foreach (var message in response.Messages)
    {
        if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
        {
            Console.WriteLine(message.Text);
        }
    }

    Console.WriteLine($"\n[Notes collected: {researchTools.NoteCount}]");
    researchTools.Clear();
    Console.Write("\n> ");
}

Console.WriteLine("Goodbye!");

/// <summary>
/// Tools available to the research agent for web searching and note-taking.
/// </summary>
public sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();

    public int NoteCount => _notes.Count;

    [Description("Search the web for information on a query. Returns search results as text.")]
    public async Task<string> WebSearch(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var response = await _httpClient.GetStringAsync(url);

            if (string.IsNullOrWhiteSpace(response) || response.Length < 50)
            {
                return $"Search results for '{query}': No detailed results available. " +
                       "Try a more specific query or different search terms.";
            }

            var trimmed = response.Length > 2000 ? response[..2000] : response;
            return $"Search results for '{query}':\n{trimmed}";
        }
        catch (HttpRequestException ex)
        {
            return $"Search failed for '{query}': {ex.Message}. Try a different query.";
        }
    }

    [Description("Save a research note with a key finding or piece of information.")]
    public string TakeNote(
        [Description("The note content to save")] string note,
        [Description("Source or context for this note")] string source)
    {
        _notes.Add($"[{source}] {note}");
        Console.WriteLine($"  📝 Note taken: {note[..Math.Min(note.Length, 60)]}...");
        return $"Note saved. Total notes: {_notes.Count}";
    }

    [Description("Retrieve all notes taken so far during this research session.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes taken yet.";

        return "Current research notes:\n" + string.Join("\n", _notes.Select((n, i) => $"{i + 1}. {n}"));
    }

    public void Clear() => _notes.Clear();
}

